const { chromium } = require('playwright');

const EMAIL = 'samwilkiedevs@gmail.com';
const PASSWORD = 'Sam18456916*';
const SESSION_FILE = '/tmp/fiverr_session_state.json';

async function humanDelay(ms) {
  const jitter = ms + Math.random() * 1000;
  await new Promise(r => setTimeout(r, jitter));
}

async function login(page) {
  console.log('🔵 Navigating to Fiverr login...');
  await page.goto('https://www.fiverr.com/users/login', { waitUntil: 'networkidle' });
  await humanDelay(3000);

  console.log('🔵 Filling email...');
  await page.fill('input[name="username"]', EMAIL);
  await humanDelay(800);

  console.log('🔵 Filling password...');
  await page.fill('input[name="password"]', PASSWORD);
  await humanDelay(800);

  console.log('🔵 Clicking login button...');
  await page.click('button[type="submit"]');
  await humanDelay(5000);

  // Check for CAPTCHA
  const captcha = await page.$('iframe[src*="captcha"]');
  if (captcha) {
    console.log('⚠️  CAPTCHA detected! Please resolve manually at:', page.url());
    console.log('   Waiting 60 seconds for you to solve it...');
    await humanDelay(60000);
  }

  console.log('✅ Login complete. URL:', page.url());
  return page.url();
}

async function setupProfile(page) {
  console.log('🔵 Navigating to profile settings...');
  await page.goto('https://www.fiverr.com/users/edit', { waitUntil: 'networkidle' });
  await humanDelay(3000);

  // Get current profile state
  const title = await page.inputValue('input[name="headline"]').catch(() => '');
  const description = await page.inputValue('textarea[name="description"]').catch(() => '');
  const fullName = await page.inputValue('input[name="full_name"]').catch(() => '');

  console.log('📋 Current profile state:');
  console.log('   Headline:', title || '(empty)');
  console.log('   Full name:', fullName || '(empty)');
  console.log('   Description length:', description.length);

  if (!title && !description) {
    console.log('⚠️  Profile appears empty — consider updating with Rebecca Ashford info');
  }
}

async function main() {
  console.log('🚀 Fiverr Automation Starting...\n');

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
    viewport: { width: 1280, height: 720 },
    ignoreHTTPSErrors: true
  });
  const page = await context.newPage();

  // Track requests to detect bot challenges
  page.on('response', response => {
    if (response.url().includes('perimeterx') || response.url().includes('captcha')) {
      console.log('🚨 Challenge detected:', response.url());
    }
  });

  try {
    await login(page);
    await setupProfile(page);

    // Save session state
    await context.storageState({ path: SESSION_FILE });
    console.log('\n💾 Session saved to', SESSION_FILE);

  } catch (error) {
    console.error('❌ Error:', error.message);
  } finally {
    await browser.close();
  }
}

main().catch(console.error);

