import { chromium } from '/home/travis/Lookitry/openclaw/node_modules/playwright/index.mjs';

async function main() {
  console.log('🚀 Studying Fiverr docs via connected browser...\n');

  const browser = await chromium.connectOverCDP('http://127.0.0.1:18800');
  const context = browser.contexts()[0];
  const pages = await context.pages();
  const fiverrPage = pages.find(p => p.url().includes('fiverr.com')) || pages[0];

  await fiverrPage.bringToFront();

  const docs = [
    { name: 'Fiverr Seller Guide', url: 'https://www.fiverr.com/resources/books/seller-guide/getting-started-with-fiverr' },
    { name: 'Fiverr Community - Gig Tips', url: 'https://www.fiverr.com/community' },
    { name: 'Fiverr Help Center', url: 'https://www.fiverr.com/support' },
  ];

  let allContent = '';

  for (const doc of docs) {
    try {
      console.log(`\n📖 Fetching: ${doc.name}...`);
      await fiverrPage.goto(doc.url, { waitUntil: 'domcontentloaded', timeout: 10000 });
      await new Promise(r => setTimeout(r, 2000));

      const text = await fiverrPage.innerText('body').catch(() => '');
      const cleaned = text.replace(/\s+/g, ' ').substring(0, 2000);
      allContent += `\n\n=== ${doc.name} ===\n${cleaned}`;
      console.log(`   Got ${text.length} chars`);
    } catch (e) {
      console.log(`   Failed: ${e.message.split('\n')[0]}`);
    }
  }

  console.log('\n\n📚 COLLECTED FIVERR KNOWLEDGE:');
  console.log(allContent);

  await browser.close();
  console.log('\n✅ Done!');
}

main().catch(console.error);

