import { chromium } from '/home/travis/Lookitry/openclaw/node_modules/playwright/index.mjs';

async function humanDelay(baseMs = 1000) {
  const jitter = baseMs + Math.random() * 2000;
  await new Promise(r => setTimeout(r, jitter));
}

async function fillField(page, selector, value, delayMs = 500) {
  await page.fill(selector, '');
  await page.fill(selector, value);
  await new Promise(r => setTimeout(r, delayMs + Math.random() * 1000));
}

async function clickButton(page, text, delayMs = 500) {
  const buttons = await page.$$('button');
  for (const btn of buttons) {
    const txt = await btn.innerText();
    if (txt.trim().toLowerCase().includes(text.toLowerCase())) {
      await btn.click();
      await new Promise(r => setTimeout(r, delayMs + Math.random() * 1000));
      return true;
    }
  }
  return false;
}

async function main() {
  console.log('🚀 Connecting to Brave via CDP...\n');

  const browser = await chromium.connectOverCDP('http://127.0.0.1:18800');
  const context = browser.contexts()[0];
  const pages = await context.pages();
  const page = pages.find(p => p.url().includes('fiverr.com')) || pages[0];

  await page.bringToFront();

  console.log('📍 Current URL:', page.url());

  // Step 1: Go to onboarding step 0
  console.log('\n🔵 Navigating to seller onboarding...');
  await page.goto('https://www.fiverr.com/seller_onboarding/0', { waitUntil: 'domcontentloaded', timeout: 15000 });
  await new Promise(r => setTimeout(r, 3000));
  console.log('📍 URL:', page.url());
  console.log('📍 Title:', await page.title());

  const body = await page.innerText('body').catch(() => '');
  console.log('\n--- Page content ---');
  console.log(body.substring(0, 1000));

  // Step 2: Fill language (English)
  console.log('\n🔵 Filling language...');
  const langBtn = await page.$('button:has-text("Add language"), button:has-text("Add language")');
  if (langBtn) {
    await langBtn.click();
    await new Promise(r => setTimeout(r, 2000));
  }

  // Get all buttons and click "Add language"
  const allButtons = await page.$$('button');
  for (const btn of allButtons) {
    const txt = await btn.innerText();
    if (txt.includes('anguage') || txt.includes('nglês') || txt.includes('English')) {
      console.log('Found language button:', txt.trim());
    }
  }

  // Step 3: Fill About/Bio
  console.log('\n🔵 Filling About/Bio...');
  const aboutSection = await page.$('textarea[name="description"], textarea');
  if (aboutSection) {
    await aboutSection.fill('');
    await aboutSection.fill(`Hi! I'm Rebecca 👋

