          text: el.innerText?.trim().substring(0, 80),
          type: el.type || el.getAttribute('role') || '',
          name: el.name || '',
          placeholder: el.placeholder || '',
          href: el.href || '',
          action: el.onclick ? 'has_onclick' : ''
        });
      });
      return els;
    });

    console.log('\n📋 All interactive elements:');
    allElements.slice(0, 50).forEach(el => {
